import Modal from "./modal";
import { Button, Input } from "../ui";
import { KycModalProps } from "@/types";

const KycModal = ({
  isOpen,
  onClose,
  phone,
  setPhone,
  occupation,
  setOccupation,
  isPending,
  onDone,
}: KycModalProps) => {
  const handleGetStarted = () => {
    setTimeout(() => {
      onDone();
    }, 900);
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      ariaLabel="kyc modal"
      maxHeight="h-fit max-h-[85vh]"
    >    
      <div className="w-full flex flex-col px-6 py-8">
        <div className="flex flex-col text-center">
          KYC
        </div>

        <Input
          label="Phone number"
          id="phone"
          type="text"
          containerClassName="mt-4"
          value={phone}
          onChange={(e) => setPhone(e.target.value)}
        />

        <Input
          label="Occupation"
          id="occupation"
          type="text"
          value={occupation}
          onChange={(e) => setOccupation(e.target.value)}
        />

        <Button
          variant="primary"
          className="w-full uppercase mt-4"
          size="large"
          onClick={handleGetStarted}
          disabled={!phone && !occupation}
          isLoading={isPending}
          iconPosition="right"
        >
          Continue
        </Button>
      </div>
    </Modal>
  );
};

export default KycModal;